                this.ls.setItem("cId", res.customerInfoList[0].customerId);
                let address;
                this.console.log(res.customerInfoList[0].userAddress.length);
                if (res.customerInfoList[0].userAddress.length > 1) {
                    address = res.customerInfoList[0].userAddress.find((item) => item.addressType == "Permanent");
                }
