    onSubmit() {
        this.submitted = true;
        if (this.applicantForms.invalid) {
            console.log("test");
            return;
        }
        let payloadObj = {};
        const control = this.applicantForms.controls['applicantDetails'].value;
        // let customerInfo: any = {}
        let addressObj = {};
        let custIdProofs = {};
        let custIdProofsArray = [];
        let addressObjArray = [];
        addressObj.addressType = control.addressType;
        addressObj.address1 = control.building + "," + control.street + "," + control.locality;
        addressObj.address2 = control.state;
        addressObj.city = control.city;
        addressObj.country = control.country;
        // addressObj.state = control.state;
        addressObj.city = control.city;
        addressObj.zipCode = control.zipCode;
        addressObj.residenceType = control.residenceType;
        addressObjArray.push(addressObj);
        custIdProofs.expiryDate = this.convertDate(control.expiryDate);
        custIdProofs.idType = control.idType;
        custIdProofs.idNumber = control.idNumber;
        custIdProofsArray.push(custIdProofs);
        payloadObj.userAddress = addressObjArray;
        payloadObj.custIdProofs = custIdProofsArray;
        payloadObj.phoneNumber = control.phoneNumber;
        payloadObj.primaryEmailAdress = control.primaryEmailAdress;
        payloadObj.prefix = control.prefix;
        payloadObj.firstName = control.firstName;
        payloadObj.middleName = control.middleName;
        payloadObj.lastName = control.lastName;
        payloadObj.cifNumber = control.cifNumber;
        payloadObj.gender = control.gender;
        payloadObj.dateOfBirth = this.convertDate(control.dateOfBirth);
        payloadObj.nationality = control.nationality;
        payloadObj.custAccount = null;
        payloadObj.landlineNumber = control.landlineNumber;
        payloadObj.createdBy = "ADMIN";
        payloadObj.createdTime = "2021-Jul-21 00:34:39";
        payloadObj.modifiedBy = "ADMIN";
        payloadObj.modifiedTime = "2021-Jul-22 11:55:38";
        // payloadObj.productCustomerId = this.ls.getItem('PRODUCT_CUSTOMER_ID');
        payloadObj.customerId = this.customerId;
        payloadObj.existingCustomer = control.existingCustomer;
        payloadObj.primaryCustomer = control.primaryCustomer;
        // payloadObj.residenceStatus = control.residenceStatus;
        payloadObj.placeOfBirth = control.placeOfBirth;
        payloadObj.countryOfResidence = control.countryOfResidence;
        payloadObj.occupationType = control.occupationType;
        // payloadObj.cifNumber = control.cifNumber;
        // payloadObj.customerInfo = customerInfo;
        // payloadObj.applicantDetails = this.applicantDetailsArray;
        console.log(payloadObj);
        this.apiService.saveDependents(payloadObj)
            .subscribe((data) => {
            console.log("Response of service 2 ---> ", data);
            this.ls.setItem('ACC_OPEN_DONE', true);
            this.accountService.refresh.next();
            if (data === 200 || data !== null) {
                this.dialogRef.close(true);
                this.snack.open('Dependent Details Saved Successfully!', 'OK', {
                    duration: 4000,
                    verticalPosition: 'top',
                    horizontalPosition: 'right'
                });
            }
            else if (data === 500) {
                this.snack.open('Not able to connect to server through 2 service', 'INTERNAL SERVER ERROR 2', {
                    duration: 4000,
                    verticalPosition: 'top',
                    horizontalPosition: 'right'
                });
            }
        }, err => {
            console.log(err);
        });
    }
