    removeApplicant(i) {
        console.log("i", i);
        this.confirmService
            .confirm({ title: "Confirm", message: "Are you sure want to remove?", ok: "Yes", cancel: "No" })
            .subscribe(res => {
            console.log("res:: removed ", res);
            if (res) {
                const control = this.applicantForms.controls['applicantDetails'];
                control.removeAt(i);
                this.cdr.markForCheck();
            }
            else
                return;
        });
    }
