class AccountInformationComponent {
    constructor(operation, apiService, sanitizer) {
        this.operation = operation;
        this.apiService = apiService;
        this.sanitizer = sanitizer;
        this.imageUrl = null;
        this.images = [];
    }
    ngOnInit() {
        this.accountInformation = this.accountInformationData;
        // this.custId=localStorage.getItem('custId');
        // console.log(this.custId)
        this.custId = localStorage.getItem('customerId');
        this.getProfile();
    }
    getProfile() {
        this.apiService.getProfileDetails(this.custId)
            .subscribe((data) => {
            this.profileData = data;
            this.imageUrl = data.profileImage;
            console.log(this.profileData, "Profile Data");
            // console.log(this.profileData.customerName,"Profile Data");
        }, (error) => {
            console.log(error);
        });
        this.getSignature(this.custId);
    }
    getSignature(custId) {
        this.apiService.fetchSignatureInfo(custId).subscribe(resp => {
            console.log("resp for signature ", resp);
            this.images = resp;
            resp.forEach((element, index) => {
                this.imageURL = resp[index].fileUrl;
                console.log("File URL", this.imageURL);
            });
        });
    }
    closeDrawer() {
        this.operation.closeDrawer();
    }
}
