class CustomerOnboardingMandateEsignComponent {
    constructor(data, dialogRef, ls, accountService, apiService, appEntryService, cdr) {
        this.data = data;
        this.dialogRef = dialogRef;
        this.ls = ls;
        this.accountService = accountService;
        this.apiService = apiService;
        this.appEntryService = appEntryService;
        this.cdr = cdr;
        this.isDone = false;
        this.signaturePadOptions = {
            'minWidth': 2,
            'canvasWidth': 700,
            'canvasHeight': 300
        };
        this.diasableDone = true;
        this.count = 0;
        this.res = { 'enable': false, 'image': null };
    }
    ngOnInit() {
        this.accountId = this.ls.getItem('accountId');
        console.log("popup response data:", this.data);
        this.isDone = this.data.isSignLater;
        this.cdr.markForCheck();
    }
    ngAfterViewInit() {
        // this.signaturePad is now available
        this.signaturePad.set('minWidth', 2);
        this.signaturePad.clear();
    }
    drawComplete() {
        console.log(this.signaturePad.toDataURL());
        const value = this.signaturePad.toDataURL();
        console.log('data :: ', value.toString().includes('data:image/png;base64'));
        if (value.toString().includes('data:image/png;base64')) {
            this.diasableDone = false;
        }
        else {
            this.diasableDone = true;
        }
    }
    drawStart() {
        console.log('begin drawing');
    }
    clearSignature() {
        this.signaturePad.clear();
    }
    savePad() {
        const base64Data = this.signaturePad.toDataURL();
        this.signatureImg = base64Data;
    }
    close1() {
        if (this.data.screen === "NewCustomerOnboarding") {
            this.dialogRef.close(this.res);
        }
        else {
            this.dialogRef.close(true);
            this.ls.setItem('enable', false);
        }
    }
    close() {
        if (this.data.screen === "NewCustomerOnboarding") {
            this.dialogRef.close(this.res);
        }
        else {
            this.dialogRef.close(true);
            this.ls.setItem('enable', true);
        }
    }
    onSubmit() {
        this.signatureImg = this.signaturePad.toDataURL();
        console.log("this.signatureImg::", this.signatureImg);
        let data = {};
        console.log("this.data::", this.data);
        this.res = { enable: true, image: this.signaturePad.toDataURL() };
        data.accountSignatureId = this.data.accountSignatureId;
        data.customerId = this.data.customerId;
        data.documentName = this.data.customerId + "Signature";
        data.documentType = "10";
        data.fileType = "image/jpeg";
        data.fileName = this.data.customerId + "signature" + ".jpg";
        data.verificationType = "New Customer Signature";
        const dataURL = this.signaturePad.toDataURL('image/png');
        const datam = atob(dataURL.substring('data:image/png;base64,'.length)), asArray = new Uint8Array(datam.length);
        for (var i = 0, len = datam.length; i < len; ++i) {
            asArray[i] = datam.charCodeAt(i);
        }
        const blob = new Blob([asArray], { type: 'image/png' });
        const txtCont = '{"noOfSignatures":' + this.data.signCount + ', "uploadModel":' + JSON.stringify(data) + ' } ';
        const uploadData = new FormData();
        uploadData.append('data', txtCont);
        uploadData.append('file', blob);
        console.log("uploadData::", uploadData);
        this.apiService.uploadSignature(uploadData).subscribe((op) => {
            console.log("op ::", op);
            if (op) {
                this.show = true;
                // this.res = op;
                console.log("this.res ::", this.res);
            }
        });
        if (this.data.screen !== "NewCustomerOnboarding") {
            this.isDone = true;
        }
        else {
            this.close();
        }
        console.log(this.isDone);
        this.ls.setItem('eSignStage', true);
    }
}
